async function fetchItem(id: number): Promise<{ name: string }> {
  if (id === 99) return Promise.reject('Not found');
  return Promise.resolve({ name: ['alpha', 'gamma', 'beta', 'delta'][id % 4] });
}

export class DataPipeline {
  async run(ids: number[]): Promise<{ id: number; label: string }[]> {
    const results = await Promise.allSettled(ids.map(id => fetchItem(id).then(item => ({ id, item }))));
    return results
      .filter(r => r.status === 'fulfilled')
      .map(r => ({ id: r.value.id, label: r.value.item.name.toUpperCase() }))
      .sort((a, b) => a.label.localeCompare(b.label));
  }
}
